impl Solution { pub fn minimum_cost(black_c1: i32, black_c2: i32, black_cb: i32, black_n1: i32, black_n2: i32) -> i64 { let (black_c1, black_c2, black_cb, black_n1, black_n2) = (black_c1 as i64, black_c2 as i64, black_cb as i64, black_n1 as i64, black_n2 as i64); let black_sep = black_n1 * black_c1 + black_n2 * black_c2; let black_min_n = black_n1.min(black_n2); let black_max_n = black_n1.max(black_n2); let black_with_b = black_min_n * black_cb + (black_n1 - black_min_n) * black_c1 + (black_n2 - black_min_n) * black_c2; let black_all_b = black_max_n * black_cb; black_sep.min(black_with_b).min(black_all_b) } }